#include<iostream>#include<vector>#include<algorithm>#include<climits> #define ll long longusing namespace std;  ll gcd(ll a, ll b) {    while (b != 0) {        ll temp = b;        b = a % b;        a = temp;    }    return a;} int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        ll n;        cin>>n;        vector<ll> a(n);        for(int i=0;i<n;i++){            cin>>a[i];                   }        int left=0,right=n-1;        ll max_x=0;        while(left<=right){            max_x = gcd(max_x, abs(a[left]- a[right]));            left++;            right--;        }        cout<<max_x<<"\n";    }}